:root {
  /*--color-bg-main: linear-gradient(135deg, #2bg000, #3b0a0a);*/
  /*--color-bg-box: linear-gradient(145deg, rgba(255, 160, 122, 0.4), rgba( 255, 69, 0, 0.4));*/
  --color-border: rgba(195, 145, 80, 0.9);
  /*--color-border: #ffffff;*/
  --color-text: rgba(255, 255, 255, 0.9);
  --color-text-soft: #ffffff;
  /*--color-shadow: 0 0 10px #ff6b6b;
  --color-shadow-strong: 0 0 20px #ff6b6b;*/
  --color-shadow: 0 0 0px #ffffff;
 --color-shadow-strong: 0 0 20px 10px rgba(255, 195, 125, 1);
  --font-main: 'Droid Sans',;
  --spacing-player: 20px;
  --color-bg-box: linear-gradient(
  145deg,
  rgba(0, 5, 8, 0.7),
  rgba(0, 5, 40, 0.6)
);
}

/* --- Container Main --- */
:root:not(:has(.css-rc3vw3)) .css-tkevr6 {
  position: relative;
  width: 100%;
  height: 100%;
  padding: 10px;
  box-sizing: border-box;
  /*background: var(--color-bg-main);*/
  /*color: var(--color-text);*/
  font-family: var(--font-main);
}

/* --- Grundlage Spielerboxen --- */
:root:not(:has(.css-rc3vw3)) .css-rtn29s,
:root:not(:has(.css-rc3vw3)) .css-hjw8x4 {
  background: var(--color-bg-box);
  color: var(--color-text);
 border: 2px solid var(--color-border);
  box-shadow: var(--color-shadow);
  transition: all 0.3s ease;
  border-radius: 12px;
  z-index: 10;
}

/* --- Hover --- */
:root:not(:has(.css-rc3vw3)) .css-rtn29s:hover,
:root:not(:has(.css-rc3vw3)) .css-hjw8x4:hover {
 transform: scale(1.03);
  cursor: pointer;
}

/* --- Navigation --- */
:root:not(:has(.css-rc3vw3)) .css-ege71s {
  background: var(--color-bg-main);
  color: var(--color-text);
}

/* --- Turn und Score --- */
:root:not(:has(.css-rc3vw3)) #ad-ext-turn .css-rrf7rv,
:root:not(:has(.css-rc3vw3)) #ad-ext-turn .score.css-156dsds,
:root:not(:has(.css-rc3vw3)) #ad-ext-turn .ad-ext-turn-throw.css-1p5spmi {
  background: var(--color-bg-box);
  color: var(--color-text);
  border: 2px solid var(--color-border);
  box-shadow: var(--color-shadow);
  text-shadow: 0 0 15px var(--color-shadow);
  transition: all 0.3s ease;
  margin-bottom: 1rem;
  border-radius: 10px;
}

:root:not(:has(.css-rc3vw3)) #ad-ext-turn .css-rrf7rv { font-size: 32px; }
:root:not(:has(.css-rc3vw3)) #ad-ext-turn .score.css-156dsds,
:root:not(:has(.css-rc3vw3)) #ad-ext-turn .ad-ext-turn-throw.css-1p5spmi {
  font-size: 100px;
  font-weight: bold;
}

:root:not(:has(.css-rc3vw3)) #ad-ext-turn .css-rrf7rv:hover,
:root:not(:has(.css-rc3vw3)) #ad-ext-turn .score.css-156dsds:hover,
:root:not(:has(.css-rc3vw3)) #ad-ext-turn .ad-ext-turn-throw.css-1p5spmi:hover {
  transform: scale(1.03);
  cursor: pointer;
}

/* --- Menu anpassen --- */
#menu-list-\:rfr\: {
  background: var(--color-bg-box) !important;
  color: var(--color-text) !important;
  border: 1px solid var(--color-border);
  border-radius: 12px;
  box-shadow: none !important;
  font-family: var(--font-main);
  padding: 0.5rem 0;
  overflow: hidden;
}
/* Scoring Anzeige bei Bust-Win-Check */
:root:not(:has(.css-rc3vw3)) .css-1dkgpmk,
:root:not(:has(.css-rc3vw3)) .css-1wlduvp,
