div.suggestion.css-881tme {
 height: 125px;
 background: var(--color-bg-box);
}
div.suggestion.css-1dkgpmk {
 animation: pulse-animation 1.5s infinite;
}
@keyframes pulse-animation {
 0% {
 transform: scale(1);
 background: rgba(110, 80, 40, 0.7);
}
 50% {
 transform: scale(1.04);
 background: rgba(180, 130, 80, 0.7);
}
 100% {
 transform: scale(1);
 background: rgba(110, 80, 40, 0.7);
}
}
